import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';

// المكونات الأساسية للموقع
import { HomeComponent } from './home/home.component';
import { AppointmentComponent } from './appointment/appointment.component';
import { AboutUsComponent } from './about-us/about-us.component';
import { LoginComponent } from './login/login.component';
import { SignupComponent } from './signup/signup.component';

// مكونات الـ Admin Layout (القائمة الجانبية)
// 🚨 تأكد من اسم المجلد: هل هو adman-layout أم admin-layout؟
import { AdminLayoutComponent } from './adman-layout/admin-layout.component';

// مكونات صفحات الـ Admin الداخلية (داخل مجلد pages)
import { AdminDashboardComponent } from './pages/admin-dashboard/admin-dashboard.component';
import { StaffComponent } from './pages/staff/staff.component';
import { PatientComponent } from './pages/patient/patient.component';
import { WardComponent } from './pages/ward/ward.component';
import { PharmacyComponent } from './pages/pharmacy/pharmacy.component';
import { MedicineComponent } from './pages/medicine/medicine.component';
import { InvoiceComponent } from './pages/invoice/invoice.component';

const routes: Routes = [
  // المسار الافتراضي يوجه لصفحة الـ Home
  { path: '', redirectTo: 'home', pathMatch: 'full' },

  // صفحات الموقع العام
  { path: 'home', component: HomeComponent },
  { path: 'login', component: LoginComponent },
  { path: 'signup', component: SignupComponent },
  { path: 'appointment', component: AppointmentComponent },
  { path: 'about-us', component: AboutUsComponent },

  // مسارات لوحة التحكم (Admin Panel)
  {
    path: 'admin',
    component: AdminLayoutComponent, // الهيكل العام للـ Admin
    children: [
      // 🌟 تم تنظيف التكرار هنا: عند الدخول لـ /admin، يفتح الـ dashboard تلقائياً
      { path: '', redirectTo: 'dashboard', pathMatch: 'full' },
      { path: 'dashboard', component: AdminDashboardComponent },
      
      // باقي صفحات الـ Admin
      { path: 'staff', component: StaffComponent },
      { path: 'patient', component: PatientComponent },
      { path: 'ward', component: WardComponent },
      { path: 'pharmacy', component: PharmacyComponent },
      { path: 'medicine', component: MedicineComponent },
      { path: 'invoice', component: InvoiceComponent },
    ]
  },

  // (اختياري) في حال تم إدخال رابط خطأ، يعيد توجيهه للصفحة الرئيسية
  // { path: '**', redirectTo: 'home' }
];

@NgModule({
  // تفعيل الـ Routing مع خيار استخدام الـ hash إذا لزم الأمر (useHash: true)
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
